from libs.database.model import Modelfrom libs.database.types import Date, Number, Date, Varchar2import datetimeclass Users(Model):    __tablename__ = 'users'    id = Number(field='id')    date_created = Date(default=datetime.datetime.now(), field='date_created')    date_modified = Date(field='date_modified')    seller_id = Number(field='seller_id')    confirmed_at = Date(field='confirmed_at')    status = Varchar2(field='status')    email = Varchar2(field='email')    name = Varchar2(field='name')    password = Varchar2(field='password')